-- ISO 9001 document import (Drive-linked, source_url).
-- Mirrors import-ikea-iway-documents.sql / import-fsc-coc-documents.sql: idempotent, re-runnable.
-- 37 files from Drive folder 'MMDI ISO 9001 - 2025 process' (single flat folder, no
-- subfolders, no exclusions needed -- all files are QMS manuals/procedures/formats).
-- content_text backfilled progressively for AI Copilot grounding, same pattern as prior categories.

on conflict (source_url) do update set
  content_text = excluded.content_text,
  file_size_bytes = excluded.file_size_bytes,
  uploaded_at = excluded.uploaded_at;